{
  "plan_description": "Set kernel.unprivileged_bpf_disabled=1 via sysctl to disable unprivileged BPF syscalls from unprivileged processes, and make the setting persistent by writing to /etc/sysctl.d/99-sysctl.conf.",
  "commands": [
    {
      "command": "sh -c \"sysctl -w kernel.unprivileged_bpf_disabled=1 && echo 'kernel.unprivileged_bpf_disabled = 1' > /etc/sysctl.d/99-sysctl.conf\""
    }
  ]
}

